   168→#### 1.3 RBAC Filter (WebFlux)
   169→**File:** `backend-mcp/src/main/java/com/aiadvent/mcp/backend/rbac/filter/RbacWebFilter.java`
   170→
   171→```java
   172→@Component
   173→@Order(Ordered.HIGHEST_PRECEDENCE + 100) // After logging, before business logic
   174→public class RbacWebFilter implements WebFilter {
   175→
   176→    private final ProfileRoleService roleService;
   177→    private final AuditLogService auditService;
   178→    private final RbacPathMatcher pathMatcher;
   179→
   180→    @Override
   181→    public Mono<Void> filter(ServerWebExchange exchange, WebFilterChain chain) {
   182→        HttpMethod method = exchange.getRequest().getMethod();
   183→        String path = exchange.getRequest().getPath().value();
   184→
   185→        // Skip non-mutation methods
   186→        if (!isMutationMethod(method)) {
   187→            return chain.filter(exchange);
   188→        }
   189→
   190→        // Skip excluded paths (health, public APIs)
   191→        if (pathMatcher.isPublicPath(path)) {
   192→            return chain.filter(exchange);
   193→        }
   194→
   195→        // Extract identity from headers
   196→        ProfileIdentity identity = extractIdentity(exchange.getRequest());
   197→        if (identity == null) {
   198→            return auditAndDeny(exchange, null, path, method, "Missing identity headers");
   199→        }
   200→
   201→        // Check required roles for path
   202→        Set<Role> requiredRoles = pathMatcher.getRequiredRoles(path, method);
   203→
   204→        return roleService.hasAnyRole(identity, requiredRoles)
   205→            .flatMap(hasRole -> {
   206→                if (hasRole) {
   207→                    auditService.logAccess(identity, path, method, "ALLOWED");
   208→                    return chain.filter(exchange);
   209→                } else {
   210→                    return auditAndDeny(exchange, identity, path, method, "Insufficient permissions");
   211→                }
   212→            })
   213→            .onErrorResume(e -> {
   214→                log.error("RBAC check failed", e);
   215→                return auditAndDeny(exchange, identity, path, method, "RBAC error: " + e.getMessage());
   216→            });
   217→    }
   218→
   219→    private Mono<Void> auditAndDeny(ServerWebExchange exchange, ProfileIdentity identity,
   220→                                     String path, HttpMethod method, String reason) {
   221→        auditService.logDenied(identity, path, method, reason);
   222→        exchange.getResponse().setStatusCode(HttpStatus.FORBIDDEN);
   223→        exchange.getResponse().getHeaders().setContentType(MediaType.APPLICATION_JSON);
   224→        String body = String.format("{\"error\":\"Forbidden\",\"reason\":\"%s\"}", reason);
   225→        DataBuffer buffer = exchange.getResponse().bufferFactory().wrap(body.getBytes());
   226→        return exchange.getResponse().writeWith(Mono.just(buffer));
   227→    }
   228→}
   229→```
