   231→#### 1.4 Profile Role Service with Caching
   232→**File:** `backend-mcp/src/main/java/com/aiadvent/mcp/backend/rbac/service/ProfileRoleService.java`
   233→
   234→```java
   235→@Service
   236→public class ProfileRoleService {
   237→
   238→    private final LoadingCache<ProfileIdentity, Set<Role>> roleCache;
   239→    private final ProfileClient profileClient;
   240→
   241→    public ProfileRoleService(ProfileClient profileClient,
   242→                              @Value("${rbac.cache.ttl-minutes:5}") int cacheTtlMinutes) {
   243→        this.profileClient = profileClient;
   244→        this.roleCache = Caffeine.newBuilder()
   245→            .expireAfterWrite(cacheTtlMinutes, TimeUnit.MINUTES)
   246→            .maximumSize(10_000)
   247→            .recordStats()
   248→            .build(this::loadRoles);
   249→    }
   250→
   251→    private Set<Role> loadRoles(ProfileIdentity identity) {
   252→        return profileClient.fetchRoles(identity);
   253→    }
   254→
   255→    public Mono<Boolean> hasAnyRole(ProfileIdentity identity, Set<Role> requiredRoles) {
   256→        if (requiredRoles.isEmpty()) {
   257→            return Mono.just(true);
   258→        }
   259→        return Mono.fromCallable(() -> roleCache.get(identity))
   260→            .subscribeOn(Schedulers.boundedElastic())
   261→            .map(userRoles -> userRoles.stream().anyMatch(requiredRoles::contains));
   262→    }
   263→
   264→    public void invalidateCache(ProfileIdentity identity) {
   265→        roleCache.invalidate(identity);
   266→    }
   267→
   268→    public CacheStats getCacheStats() {
   269→        return roleCache.stats();
   270→    }
   271→}
   272→```
