   274→#### 1.5 Audit Log Service
   275→**File:** `backend-mcp/src/main/java/com/aiadvent/mcp/backend/rbac/service/AuditLogService.java`
   276→
   277→```java
   278→@Service
   279→public class AuditLogService {
   280→
   281→    private final AuditLogRepository repository;
   282→    private final ExecutorService asyncExecutor = Executors.newFixedThreadPool(4);
   283→
   284→    public void logAccess(ProfileIdentity identity, String path, HttpMethod method, String result) {
   285→        asyncLog(() -> {
   286→            AuditLogEntry entry = new AuditLogEntry();
   287→            entry.setActorNamespace(identity.namespace());
   288→            entry.setActorReference(identity.reference());
   289→            entry.setAction("ACCESS");
   290→            entry.setTargetResource(path);
   291→            entry.setHttpMethod(method.name());
   292→            entry.setHttpPath(path);
   293→            entry.setResult(result);
   294→            repository.save(entry);
   295→        });
   296→    }
   297→
   298→    public void logDenied(ProfileIdentity identity, String path, HttpMethod method, String reason) {
   299→        asyncLog(() -> {
   300→            AuditLogEntry entry = new AuditLogEntry();
   301→            if (identity != null) {
   302→                entry.setActorNamespace(identity.namespace());
   303→                entry.setActorReference(identity.reference());
   304→            }
   305→            entry.setAction("DENIED");
   306→            entry.setTargetResource(path);
   307→            entry.setHttpMethod(method.name());
   308→            entry.setHttpPath(path);
   309→            entry.setResult("DENIED");
   310→            entry.setMetadata(Map.of("reason", reason));
   311→            repository.save(entry);
   312→        });
   313→    }
   314→
   315→    public void logRoleChange(ProfileIdentity actor, ProfileIdentity target,
   316→                              String action, Set<Role> roles) {
   317→        asyncLog(() -> {
   318→            AuditLogEntry entry = new AuditLogEntry();
   319→            entry.setActorNamespace(actor.namespace());
   320→            entry.setActorReference(actor.reference());
   321→            entry.setAction(action); // GRANT or REVOKE
   322→            entry.setTargetProfileNamespace(target.namespace());
   323→            entry.setTargetProfileReference(target.reference());
   324→            entry.setResult("SUCCESS");
   325→            entry.setMetadata(Map.of("roles", roles));
   326→            repository.save(entry);
   327→        });
   328→    }
   329→
   330→    private void asyncLog(Runnable task) {
   331→        asyncExecutor.submit(() -> {
   332→            try {
   333→                task.run();
   334→            } catch (Exception e) {
   335→                log.error("Failed to write audit log", e);
   336→            }
   337→        });
   338→    }
   339→}
   340→```
