   349→### Phase 2: Profile Service Integration (Days 4-5)
   350→**Goal:** Connect to existing profile service for role resolution
   351→
   352→#### 2.1 Profile Client
   353→**File:** `backend-mcp/src/main/java/com/aiadvent/mcp/backend/rbac/client/ProfileClient.java`
   354→
   355→```java
   356→@Component
   357→public class ProfileClient {
   358→
   359→    private final WebClient webClient;
   360→    private final String profileServiceUrl;
   361→
   362→    public ProfileClient(@Value("${profile.service.url}") String profileServiceUrl,
   363→                         WebClient.Builder webClientBuilder) {
   364→        this.profileServiceUrl = profileServiceUrl;
   365→        this.webClient = webClientBuilder.baseUrl(profileServiceUrl).build();
   366→    }
   367→
   368→    public Set<Role> fetchRoles(ProfileIdentity identity) {
   369→        try {
   370→            ProfileResponse response = webClient.get()
   371→                .uri("/api/profiles/{namespace}/{reference}", identity.namespace(), identity.reference())
   372→                .retrieve()
   373→                .bodyToMono(ProfileResponse.class)
   374→                .timeout(Duration.ofSeconds(2))
   375→                .block();
   376→
   377→            return response != null && response.roles() != null
   378→                ? response.roles().stream().map(Role::valueOf).collect(Collectors.toSet())
   379→                : Set.of();
   380→        } catch (Exception e) {
   381→            log.error("Failed to fetch roles for {}", identity, e);
   382→            // Fail-closed: return empty set (deny access)
   383→            return Set.of();
   384→        }
   385→    }
   386→}
   387→```
