   439→#### 3.1 Extend Profile Store with SSE
   440→**File:** `frontend/src/lib/profileStore.ts` (modifications)
   441→
   442→```typescript
   443→// Add to ProfileStoreState
   444→type ProfileStoreState = {
   445→  // ... existing fields
   446→  roleVersion: number; // Incremented on role change
   447→  lastRoleSync: string | null;
   448→  subscribeToRoleChanges: () => () => void;
   449→};
   450→
   451→// Add to store implementation
   452→export const useProfileStore = create<ProfileStoreState>()(
   453→  persist(
   454→    (set, get) => ({
   455→      // ... existing initial state
   456→      roleVersion: 0,
   457→      lastRoleSync: null,
   458→
   459→      subscribeToRoleChanges: () => {
   460→        const { namespace, reference, channel, devToken } = getActiveProfileSelection();
   461→        if (!namespace || !reference) return () => {};
   462→
   463→        const params = new URLSearchParams();
   464→        params.set('namespace', namespace);
   465→        params.set('reference', reference);
   466→        if (channel) params.set('channel', channel);
   467→        if (devToken) params.set('token', devToken);
   468→
   469→        const eventSource = new EventSource(
   470→          `${API_BASE_URL}/api/profiles/role-events?${params.toString()}`
   471→        );
   472→
   473→        eventSource.addEventListener('role-change', (event) => {
   474→          const data = JSON.parse(event.data);
   475→          set((state) => ({
   476→            profile: state.profile ? {
   477→              ...state.profile,
   478→              roles: data.roles,
   479→              updatedAt: data.timestamp,
   480→            } : null,
   481→            roleVersion: state.roleVersion + 1,
   482→            lastRoleSync: new Date().toISOString(),
   483→          }));
   484→        });
   485→
   486→        eventSource.onerror = () => {
   487→          // Auto-reconnect handled by browser, but we log it
   488→          console.warn('Role events connection error, will retry...');
   489→        };
   490→
   491→        return () => eventSource.close();
   492→      },
   493→    }),
   494→    // ... existing persist config
   495→  ),
   496→);
