   499→#### 3.2 Create useRoleGuard Hook
   500→**File:** `frontend/src/lib/useRoleGuard.ts` (new)
   501→
   502→```typescript
   503→import { useEffect, useMemo } from 'react';
   504→import { useProfileStore } from './profileStore';
   505→
   506→export function useRoleGuard(requiredRole?: string) {
   507→  const roles = useProfileStore((state) => state.profile?.roles ?? []);
   508→  const roleVersion = useProfileStore((state) => state.roleVersion);
   509→
   510→  // Subscribe to role changes on mount
   511→  useEffect(() => {
   512→    const unsubscribe = useProfileStore.getState().subscribeToRoleChanges();
   513→    return unsubscribe;
   514→  }, []);
   515→
   516→  const hasRole = useMemo(() => {
   517→    if (!requiredRole) return true;
   518→    return roles.some((role) => role === requiredRole);
   519→  }, [roles, requiredRole, roleVersion]);
   520→
   521→  const hasAnyRole = useMemo(() => {
   522→    return (roleCodes: string[]) => roles.some((role) => roleCodes.includes(role));
   523→  }, [roles, roleVersion]);
   524→
   525→  const hasAllRoles = useMemo(() => {
   526→    return (roleCodes: string[]) => roleCodes.every((role) => roles.includes(role));
   527→  }, [roles, roleVersion]);
   528→
   529→  return {
   530→    roles,
   531→    hasRole,
   532→    hasAnyRole,
   533→    hasAllRoles,
   534→    isAdmin: roles.includes('admin'),
   535→    roleVersion,
   536→  };
   537→}
   538→```
