   588→### Phase 4: SSE Role Events Endpoint (Days 9-10)
   589→**Goal:** Backend SSE endpoint for role change notifications
   590→
   591→#### 4.1 Role Event Service
   592→**File:** `backend-mcp/src/main/java/com/aiadvent/mcp/backend/rbac/service/RoleEventService.java`
   593→
   594→```java
   595→@Service
   596→public class RoleEventService {
   597→
   598→    private final Map<ProfileIdentity, Sinks.Many<RoleChangeEvent>> subscribers = new ConcurrentHashMap<>();
   599→
   600→    public Flux<RoleChangeEvent> subscribe(ProfileIdentity identity) {
   601→        Sinks.Many<RoleChangeEvent> sink = Sinks.many().multicast().onBackpressureBuffer();
   602→        subscribers.put(identity, sink);
   603→
   604→        return sink.asFlux()
   605→            .doOnCancel(() -> subscribers.remove(identity))
   606→            .doOnTerminate(() -> subscribers.remove(identity));
   607→    }
   608→
   609→    public void notifyRoleChange(ProfileIdentity identity, List<String> roles) {
   610→        Sinks.Many<RoleChangeEvent> sink = subscribers.get(identity);
   611→        if (sink != null) {
   612→            sink.tryEmitNext(new RoleChangeEvent(roles, Instant.now()));
   613→        }
   614→    }
   615→
   616→    public void broadcastRoleChange(ProfileIdentity target, List<String> roles) {
   617→        notifyRoleChange(target, roles);
   618→    }
   619→
   620→    public record RoleChangeEvent(List<String> roles, Instant timestamp) {}
   621→}
