    69→
    70→def osName = System.getProperty('os.name').toLowerCase(Locale.ROOT)
    71→def archName = System.getProperty('os.arch').toLowerCase(Locale.ROOT)
    72→def treeSitterOs = (osName.contains('mac')) ? 'macos' : (osName.contains('win') ? 'windows' : 'linux')
    73→def treeSitterArch = (archName.contains('aarch64') || archName.contains('arm64')) ? 'arm64' : (archName.contains('x86') && !archName.contains('64')) ? 'x86' : 'x86_64'
    74→def treeSitterLibPrefix = osName.contains('win') ? '' : 'lib'
    75→def treeSitterLibExt = osName.contains('mac') ? '.dylib' : (osName.contains('win') ? '.dll' : '.so')
    76→
    77→def treeSitterLanguages = [
    78→        [name: 'java', repo: 'tree-sitter-java', sources: ['src/parser.c']],
    79→        [name: 'kotlin', repo: 'tree-sitter-kotlin', sources: ['src/parser.c', 'src/scanner.c']],
    80→        [name: 'typescript', repo: 'tree-sitter-typescript/typescript', sources: ['src/parser.c', 'src/scanner.c'], includes: ['../common']],
    81→        [name: 'javascript', repo: 'tree-sitter-javascript', sources: ['src/parser.c', 'src/scanner.c']],
    82→        [name: 'python', repo: 'tree-sitter-python', sources: ['src/parser.c', 'src/scanner.c']],
    83→        [name: 'go', repo: 'tree-sitter-go', sources: ['src/parser.c']]
    84→]
    85→
    86→def treeSitterOutputDir = layout.buildDirectory.dir("treesitter/${treeSitterOs}/${treeSitterArch}")
    87→def javaTreeSitterLibDir = layout.buildDirectory.dir("generated/java-tree-sitter/${treeSitterOs}/${treeSitterArch}")
    88→treeSitterLanguages.each { language ->
    89→    def capitalized = language.name.capitalize()
    90→    tasks.register("treeSitterCompile${capitalized}") {
    91→        group = 'tree-sitter'
    92→        description = "Build Tree-sitter library for ${language.name}"
    93→        def repoDir = project.layout.projectDirectory.dir("treesitter/${language.repo}").asFile
    94→        def includes = (language.includes ?: [])
    95→        inputs.files(language.sources.collect { new File(repoDir, it) })
    96→        outputs.file(treeSitterOutputDir.map { it.file("${treeSitterLibPrefix}tree-sitter-${language.name}${treeSitterLibExt}") })
    97→        doLast {
    98→            treeSitterOutputDir.get().asFile.mkdirs()
    99→            def includeFlags = [new File(repoDir, 'src'), new File(repoDir, 'src/tree_sitter')]
   100→                    .plus(includes.collect { new File(repoDir, it) })
   101→                    .collectMany { ['-I', it.absolutePath] }
   102→            def compilerArgs = []
   103→            compilerArgs += ['cc', '-shared', '-fPIC', '-O3', '-std=c99']
   104→            if (osName.contains('mac')) {
   105→                compilerArgs += ['-undefined', 'dynamic_lookup']
   106→            }
   107→            compilerArgs += includeFlags
   108→            compilerArgs += language.sources.collect { new File(repoDir, it).absolutePath }
   109→            def outputFile = treeSitterOutputDir.get().file("${treeSitterLibPrefix}tree-sitter-${language.name}${treeSitterLibExt}").asFile
   110→            compilerArgs += ['-o', outputFile.absolutePath]
   111→            exec {
   112→                commandLine compilerArgs
   113→            }
   114→        }
   115→    }
   116→}
   117→
   118→tasks.register('treeSitterBuild') {
   119→    group = 'tree-sitter'
   120→    description = 'Builds all configured Tree-sitter grammars'
   121→    dependsOn treeSitterLanguages.collect { language -> tasks.named("treeSitterCompile${language.name.capitalize()}") }
   122→}
   123→
   124→tasks.register('treeSitterVerify') {
   125→    group = 'verification'
   126→    description = 'Verifies Tree-sitter libraries exist for the current platform'
   127→    dependsOn 'treeSitterBuild'
   128→    doLast {
   129→        def dir = treeSitterOutputDir.get().asFile
   130→        if (!dir.exists() || dir.listFiles()?.length == 0) {
   131→            throw new GradleException("Tree-sitter libraries were not built")
   132→        }
   133→        println "Tree-sitter libraries available in ${dir}:"
   134→        dir.listFiles().sort().each { println " - ${it.name} (${it.length()} bytes)" }
   135→    }
   136→}
   137→
   138→def syncTreeSitterResources = tasks.register('syncTreeSitterResources', Sync) {
   139→    dependsOn 'treeSitterBuild'
   140→    from treeSitterOutputDir
   141→    into layout.buildDirectory.dir("generated/treesitter/${treeSitterOs}/${treeSitterArch}")
   142→}
   143→
   144→def syncJavaTreeSitterCore = tasks.register('syncJavaTreeSitterCore', Copy) {
   145→    group = 'tree-sitter'
   146→    description = 'Copies libjava-tree-sitter.* from dependency into resources'
   147→    def coreJar = configurations.runtimeClasspath.find { it.name.startsWith('java-tree-sitter-') }
   148→    from(coreJar ? zipTree(coreJar) : []) {
   149→        include 'libjava-tree-sitter.*'
   150→        rename { _ -> "${treeSitterLibPrefix}java-tree-sitter${treeSitterLibExt}" }
   151→    }
   152→    duplicatesStrategy = DuplicatesStrategy.EXCLUDE
   153→    into javaTreeSitterLibDir
   154→    onlyIf { coreJar != null }
   155→}
   156→
   157→tasks.named('processResources') {
   158→    dependsOn syncTreeSitterResources
   159→    dependsOn syncJavaTreeSitterCore
   160→    from(syncTreeSitterResources.map { it.destinationDir }) {
