package com.aiadvent.mcp.backend.rbac.config;

import java.util.Collections;
import java.util.List;
import org.springframework.boot.context.properties.ConfigurationProperties;

/**
 * Configuration properties for RBAC system.
 */
@ConfigurationProperties(prefix = "rbac")
public class RbacProperties {

    private boolean enabled = false;
    private boolean auditOnly = true;
    private int cacheTtlMinutes = 5;
    private List<PathRule> protectedPaths = Collections.emptyList();
    private List<String> publicPaths = Collections.emptyList();

    public boolean isEnabled() {
        return enabled;
    }

    public void setEnabled(boolean enabled) {
        this.enabled = enabled;
    }

    public boolean isAuditOnly() {
        return auditOnly;
    }

    public void setAuditOnly(boolean auditOnly) {
        this.auditOnly = auditOnly;
    }

    public int getCacheTtlMinutes() {
        return cacheTtlMinutes;
    }

    public void setCacheTtlMinutes(int cacheTtlMinutes) {
        this.cacheTtlMinutes = cacheTtlMinutes;
    }

    public List<PathRule> getProtectedPaths() {
        return protectedPaths;
    }

    public void setProtectedPaths(List<PathRule> protectedPaths) {
        this.protectedPaths = protectedPaths;
    }

    public List<String> getPublicPaths() {
        return publicPaths;
    }

    public void setPublicPaths(List<String> publicPaths) {
        this.publicPaths = publicPaths;
    }

    /**
     * Path rule for protected routes.
     */
    public static class PathRule {
        private String path;
        private List<String> methods = Collections.emptyList();
        private List<String> requiredRoles = Collections.emptyList();

        public String getPath() {
            return path;
        }

        public void setPath(String path) {
            this.path = path;
        }

        public List<String> getMethods() {
            return methods;
        }

        public void setMethods(List<String> methods) {
            this.methods = methods;
        }

        public List<String> getRequiredRoles() {
            return requiredRoles;
        }

        public void setRequiredRoles(List<String> requiredRoles) {
            this.requiredRoles = requiredRoles;
        }
    }
}

package com.aiadvent.mcp.backend.rbac.config;

import com.aiadvent.mcp.backend.rbac.matcher.RbacPathMatcher;
import com.aiadvent.mcp.backend.rbac.persistence.AuditLogRepository;
import com.aiadvent.mcp.backend.rbac.service.AuditLogService;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import org.springframework.boot.context.properties.EnableConfigurationProperties;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

/**
 * Spring configuration for RBAC system.
 */
@Configuration
@EnableConfigurationProperties(RbacProperties.class)
public class RbacConfiguration {

    @Bean
    public RbacPathMatcher rbacPathMatcher(RbacProperties rbacProperties) {
        return new RbacPathMatcher(rbacProperties);
    }

    @Bean
    public AuditLogService auditLogService(AuditLogRepository auditLogRepository) {
        ExecutorService executor = Executors.newFixedThreadPool(4, r -> {
            Thread t = new Thread(r, "audit-log-" + System.currentTimeMillis());
            t.setDaemon(true);
            return t;
        });
        return new AuditLogService(auditLogRepository, executor);
    }
}

package com.aiadvent.mcp.backend.rbac.matcher;

import com.aiadvent.mcp.backend.rbac.config.RbacProperties;
import com.aiadvent.mcp.backend.rbac.config.RbacProperties.PathRule;
import java.util.Collections;
import java.util.List;
import java.util.Optional;
import org.springframework.http.HttpMethod;
import org.springframework.util.AntPathMatcher;
import org.springframework.util.PathMatcher;

/**
 * Path matching logic for protected routes.
 */
public class RbacPathMatcher {

    private final RbacProperties properties;
    private final PathMatcher pathMatcher;

    public RbacPathMatcher(RbacProperties properties) {
        this.properties = properties;
        this.pathMatcher = new AntPathMatcher();
    }

    /**
     * Check if the given path is public (excluded from RBAC).
     *
     * @param path the request path
     * @return true if the path is public
     */
    public boolean isPublicPath(String path) {
        if (properties.getPublicPaths() == null) {
            return false;
        }
        return properties.getPublicPaths().stream()
                .anyMatch(pattern -> pathMatcher.match(pattern, path));
    }

    /**
     * Check if the given path and method should be protected.
     *
     * @param path   the request path
     * @param method the HTTP method
     * @return true if the path/method requires RBAC check
     */
    public boolean isProtectedPath(String path, String method) {
        if (properties.getProtectedPaths() == null) {
            return isMutationMethod(method);
        }
        return properties.getProtectedPaths().stream()
                .anyMatch(rule -> matchesRule(rule, path, method));
    }

    /**
     * Get required roles for the given path and method.
     *
     * @param path   the request path
     * @param method the HTTP method
     * @return list of required roles, empty if none defined
     */
    public List<String> getRequiredRoles(String path, String method) {
        if (properties.getProtectedPaths() == null) {
            return Collections.emptyList();
        }
        return properties.getProtectedPaths().stream()
                .filter(rule -> matchesRule(rule, path, method))
                .findFirst()
                .map(PathRule::getRequiredRoles)
                .orElse(Collections.emptyList());
    }

    /**
     * Check if the HTTP method is a mutation method (POST, PUT, DELETE, PATCH).
     *
     * @param method the HTTP method
     * @return true if it's a mutation method
     */
    public boolean isMutationMethod(String method) {
        if (method == null) {
            return false;
        }
        String upper = method.toUpperCase();
        return upper.equals("POST") || upper.equals("PUT")
                || upper.equals("DELETE") || upper.equals("PATCH");
    }

    /**
     * Check if the HTTP method should be skipped (GET, HEAD, OPTIONS).
     *
     * @param method the HTTP method
     * @return true if the method should be skipped
     */
    public boolean shouldSkipMethod(String method) {
        if (method == null) {
            return false;
        }
        String upper = method.toUpperCase();
        return upper.equals("GET") || upper.equals("HEAD") || upper.equals("OPTIONS");
    }

    private boolean matchesRule(PathRule rule, String path, String method) {
        if (rule.getPath() == null || !pathMatcher.match(rule.getPath(), path)) {
            return false;
        }
        if (rule.getMethods() == null || rule.getMethods().isEmpty()) {
            return true;
        }
        return rule.getMethods().stream()
                .anyMatch(m -> m.equalsIgnoreCase(method));
    }
}

package com.aiadvent.mcp.backend.rbac.service;

import com.aiadvent.mcp.backend.rbac.domain.ProfileIdentity;
import com.aiadvent.mcp.backend.rbac.domain.Role;
import com.aiadvent.mcp.backend.rbac.persistence.AuditLogEntity;
import com.aiadvent.mcp.backend.rbac.persistence.AuditLogRepository;
import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import java.util.List;
import java.util.Set;
import java.util.concurrent.ExecutorService;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

/**
 * Async audit logging service for RBAC operations.
 */
public class AuditLogService {

    private static final Logger log = LoggerFactory.getLogger(AuditLogService.class);
    private static final ObjectMapper objectMapper = new ObjectMapper();

    private final AuditLogRepository auditLogRepository;
    private final ExecutorService executor;

    public AuditLogService(AuditLogRepository auditLogRepository, ExecutorService executor) {
        this.auditLogRepository = auditLogRepository;
        this.executor = executor;
    }

    /**
     * Log an access attempt (allowed or denied).
     *
     * @param identity    the actor identity
     * @param action      the action being performed
     * @param resource    the target resource
     * @param httpMethod  the HTTP method
     * @param httpPath    the HTTP path
     * @param allowed     whether access was allowed
     * @param roles       the roles the actor has
     */
    public void logAccess(
            ProfileIdentity identity,
            String action,
            String resource,
            String httpMethod,
            String httpPath,
            boolean allowed,
            Set<Role> roles) {

        executor.submit(() -> {
            try {
                AuditLogEntity entry = new AuditLogEntity();
                entry.setActorNamespace(identity.namespace());
                entry.setActorReference(identity.reference());
                entry.setAction(action);
                entry.setTargetResource(resource);
                entry.setResult(allowed ? "ALLOWED" : "DENIED");
                entry.setHttpMethod(httpMethod);
                entry.setHttpPath(httpPath);

                JsonNode metadata = objectMapper.valueToTree(
                        new AuditMetadata(roles != null ? roles.stream().map(Role::name).toList() : List.of()));
                entry.setMetadata(metadata);

                auditLogRepository.save(entry);
                log.debug("Audit log saved for {}: {} {} -> {}",
                        identity, httpMethod, httpPath, allowed ? "ALLOWED" : "DENIED");
            } catch (Exception e) {
                log.error("Failed to save audit log for {}: {}", identity, e.getMessage(), e);
            }
        });
    }

    /**
     * Log a denied access attempt.
     *
     * @param identity   the actor identity
     * @param action     the action being performed
     * @param resource   the target resource
     * @param httpMethod the HTTP method
     * @param httpPath   the HTTP path
     * @param reason     the reason for denial
     * @param roles      the roles the actor has
     */
    public void logDenied(
            ProfileIdentity identity,
            String action,
            String resource,
            String httpMethod,
            String httpPath,
            String reason,
            Set<Role> roles) {

        executor.submit(() -> {
            try {
                AuditLogEntity entry = new AuditLogEntity();
                entry.setActorNamespace(identity.namespace());
                entry.setActorReference(identity.reference());
                entry.setAction(action);
                entry.setTargetResource(resource);
                entry.setResult("DENIED");
                entry.setHttpMethod(httpMethod);
                entry.setHttpPath(httpPath);

                JsonNode metadata = objectMapper.valueToTree(
                        new AuditDeniedMetadata(
                                roles != null ? roles.stream().map(Role::name).toList() : List.of(),
                                reason));
                entry.setMetadata(metadata);

                auditLogRepository.save(entry);
                log.debug("Audit log saved for denied access {}: {} {} - reason: {}",
                        identity, httpMethod, httpPath, reason);
            } catch (Exception e) {
                log.error("Failed to save audit log for {}: {}", identity, e.getMessage(), e);
            }
        });
    }

    /**
     * Log a role change operation (GRANT/REVOKE).
     *
     * @param actorIdentity  the actor performing the change
     * @param targetIdentity the target profile being changed
     * @param action         the action (GRANT or REVOKE)
     * @param role           the role being granted/revoked
     * @param success        whether the operation succeeded
     */
    public void logRoleChange(
            ProfileIdentity actorIdentity,
            ProfileIdentity targetIdentity,
            String action,
            Role role,
            boolean success) {

        executor.submit(() -> {
            try {
                AuditLogEntity entry = new AuditLogEntity();
                entry.setActorNamespace(actorIdentity.namespace());
                entry.setActorReference(actorIdentity.reference());
                entry.setAction(action);
                entry.setTargetProfileNamespace(targetIdentity.namespace());
                entry.setTargetProfileReference(targetIdentity.reference());
                entry.setResult(success ? "SUCCESS" : "FAILED");

                JsonNode metadata = objectMapper.valueToTree(
                        new RoleChangeMetadata(role.name()));
                entry.setMetadata(metadata);

                auditLogRepository.save(entry);
                log.debug("Audit log saved for role change {}: {} role {} to {} -> {}",
                        actorIdentity, action, role, targetIdentity, success ? "SUCCESS" : "FAILED");
            } catch (Exception e) {
                log.error("Failed to save role change audit log: {}", e.getMessage(), e);
            }
        });
    }

    /**
     * Shutdown the executor service gracefully.
     */
    public void shutdown() {
        executor.shutdown();
    }

    // Metadata records for JSON serialization
    private record AuditMetadata(List<String> roles) {}

    private record AuditDeniedMetadata(List<String> roles, String reason) {}

    private record RoleChangeMetadata(String role) {}
}

package com.aiadvent.mcp.backend.rbac.filter;

import com.aiadvent.mcp.backend.rbac.domain.ProfileIdentity;
import com.aiadvent.mcp.backend.rbac.domain.Role;
import com.aiadvent.mcp.backend.rbac.matcher.RbacPathMatcher;
import com.aiadvent.mcp.backend.rbac.service.AuditLogService;
import com.fasterxml.jackson.core.JsonProcessingException;
import com.fasterxml.jackson.databind.ObjectMapper;
import java.nio.charset.StandardCharsets;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.Set;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.core.Ordered;
import org.springframework.core.annotation.Order;
import org.springframework.core.io.buffer.DataBuffer;
import org.springframework.http.HttpStatus;
import org.springframework.http.MediaType;
import org.springframework.http.server.reactive.ServerHttpRequest;
import org.springframework.http.server.reactive.ServerHttpResponse;
import org.springframework.stereotype.Component;
import org.springframework.web.server.ServerWebExchange;
import org.springframework.web.server.WebFilter;
import org.springframework.web.server.WebFilterChain;
import reactor.core.publisher.Mono;

/**
 * WebFlux filter for RBAC enforcement on mutation APIs.
 */
@Component
@Order(Ordered.HIGHEST_PRECEDENCE + 100)
public class RbacWebFilter implements WebFilter {

    private static final Logger log = LoggerFactory.getLogger(RbacWebFilter.class);
    private static final ObjectMapper objectMapper = new ObjectMapper();
    private static final String PROFILE_KEY_HEADER = "X-Profile-Key";

    private final RbacPathMatcher pathMatcher;
    private final AuditLogService auditLogService;

    public RbacWebFilter(RbacPathMatcher pathMatcher, AuditLogService auditLogService) {
        this.pathMatcher = pathMatcher;
        this.auditLogService = auditLogService;
    }

    @Override
    public Mono<Void> filter(ServerWebExchange exchange, WebFilterChain chain) {
        ServerHttpRequest request = exchange.getRequest();
        String path = request.getPath().value();
        String method = request.getMethod().name();

        // Skip non-mutation methods
        if (pathMatcher.shouldSkipMethod(method)) {
            return chain.filter(exchange);
        }

        // Skip public paths
        if (pathMatcher.isPublicPath(path)) {
            return chain.filter(exchange);
        }

        // Only protect mutation methods or explicitly configured paths
        if (!pathMatcher.isMutationMethod(method) && !pathMatcher.isProtectedPath(path, method)) {
            return chain.filter(exchange);
        }

        // Extract identity from header
        String profileKey = request.getHeaders().getFirst(PROFILE_KEY_HEADER);
        if (profileKey == null || profileKey.isBlank()) {
            return sendForbiddenResponse(exchange, "Missing or empty X-Profile-Key header");
        }

        ProfileIdentity identity = parseProfileKey(profileKey);
        if (identity == null) {
            return sendForbiddenResponse(exchange, "Invalid X-Profile-Key format. Expected: namespace:reference");
        }

        // Get required roles for this path/method
        List<String> requiredRoles = pathMatcher.getRequiredRoles(path, method);

        // Get roles for identity (mock/stub for now - will be replaced with profile service in I3)
        Set<Role> userRoles = getMockRoles(identity);

        // Check if user has any of the required roles
        boolean hasRequiredRole = requiredRoles.isEmpty() ||
                requiredRoles.stream().anyMatch(role ->
                        userRoles.stream().anyMatch(userRole -> userRole.name().equalsIgnoreCase(role)));

        if (!hasRequiredRole) {
            auditLogService.logDenied(
                    identity,
                    "ACCESS",
                    path,
                    method,
                    path,
                    "Insufficient permissions. Required roles: " + requiredRoles,
                    userRoles
            );
            return sendForbiddenResponse(exchange,
                    "Access denied. Required roles: " + requiredRoles);
        }

        // Log allowed access
        auditLogService.logAccess(
                identity,
                "ACCESS",
                path,
                method,
                path,
                true,
                userRoles
        );

        return chain.filter(exchange);
    }

    /**
     * Parse profile key from header format: namespace:reference
     */
    private ProfileIdentity parseProfileKey(String profileKey) {
        if (profileKey == null || !profileKey.contains(":")) {
            return null;
        }
        String[] parts = profileKey.split(":", 2);
        if (parts.length != 2 || parts[0].isBlank() || parts[1].isBlank()) {
            return null;
        }
        try {
            return new ProfileIdentity(parts[0].trim(), parts[1].trim());
        } catch (IllegalArgumentException e) {
            return null;
        }
    }

    /**
     * Mock role service - returns roles based on namespace.
     * This will be replaced with actual profile service integration in I3.
     */
    private Set<Role> getMockRoles(ProfileIdentity identity) {
        // Mock logic: admin namespace gets ADMIN role, test namespace gets USER role
        String ns = identity.namespace().toLowerCase();
        if (ns.equals("admin") || ns.equals("github")) {
            return Set.of(Role.ADMIN, Role.USER, Role.VIEWER);
        } else if (ns.equals("user") || ns.equals("local")) {
            return Set.of(Role.USER, Role.VIEWER);
        } else if (ns.equals("viewer")) {
            return Set.of(Role.VIEWER);
        }
        // Default: VIEWER only
        return Set.of(Role.VIEWER);
    }

    /**
     * Send a 403 Forbidden response with JSON body.
     */
    private Mono<Void> sendForbiddenResponse(ServerWebExchange exchange, String message) {
        ServerHttpResponse response = exchange.getResponse();
        response.setStatusCode(HttpStatus.FORBIDDEN);
        response.getHeaders().setContentType(MediaType.APPLICATION_JSON);

        Map<String, Object> errorBody = new HashMap<>();
        errorBody.put("status", 403);
        errorBody.put("error", "Forbidden");
        errorBody.put("message", message);
        errorBody.put("path", exchange.getRequest().getPath().value());

        try {
            byte[] bytes = objectMapper.writeValueAsBytes(errorBody);
            DataBuffer buffer = response.bufferFactory().wrap(bytes);
            return response.writeWith(Mono.just(buffer));
        } catch (Exception e) {
            log.error("Failed to write error response", e);
            byte[] bytes = ("{\"status\":403,\"error\":\"Forbidden\"}").getBytes(StandardCharsets.UTF_8);
            DataBuffer buffer = response.bufferFactory().wrap(bytes);
            return response.writeWith(Mono.just(buffer));
        }
    }
}

